"""ResolvePhase — 도구 검색, LLM 호출."""

from __future__ import annotations

import logging

from mantis.exceptions import LLMError
from mantis.executor.protocol import ExecutionContext
from mantis.executor.phases.protocol import PhaseResult

logger = logging.getLogger(__name__)


class DefaultResolve:
    """기본 ResolvePhase.

    1. 도구 스키마 조회
    2. 도구 검색 (search Provider가 있고 도구 15개+ → 자동 필터링)
    3. on_before_llm 미들웨어
    4. LLM 호출
    """

    name = "resolve"

    async def run(self, ctx: ExecutionContext) -> PhaseResult:
        tools_schema = ctx.registry.to_openai_tools(session_id=ctx.session_id)

        # 자동 도구 검색 (search Provider 있으면)
        if ctx.search is not None and len(tools_schema) > 15:
            try:
                query = ctx.run_ctx.last_user_message
                relevant_names = ctx.search.search(query, top_k=10)
                if relevant_names:
                    name_set = set(relevant_names)
                    tools_schema = [
                        t for t in tools_schema
                        if t.get("function", {}).get("name") in name_set
                    ]
            except Exception as e:
                logger.warning("도구 검색 실패, 전체 도구 사용: %s", e)

        # 미들웨어 on_before_llm
        for mw in ctx.middlewares:
            tools_schema = await mw.on_before_llm(ctx.run_ctx, tools_schema)

        # LLM 호출
        try:
            response = await ctx.model.generate(
                messages=ctx.conversation.to_messages(),
                tools=tools_schema if tools_schema else None,
            )
        except Exception as e:
            raise LLMError(f"모델 호출 실패: {e}") from e

        return PhaseResult(
            status="continue",
            data={"response": response},
        )
